<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8">
<title>Mini Desktop</title>
<style>
  *{box-sizing:border-box;margin:0;padding:0;font-family:sans-serif;}
  body,html{height:100%;background:#222;color:#eee;overflow:hidden;}
  #desktop{position:absolute;width:100%;height:100%;display:flex;flex-direction:column;background:url('data:image/svg+xml,<svg xmlns="http://www.w3.org/2000/svg" width="400" height="400"><rect width="400" height="400" fill="%23222"/><circle cx="200" cy="200" r="150" fill="%23333"/></svg>') center/cover;}
  #taskbar{height:40px;background:#111;display:flex;align-items:center;padding-left:5px;border-top:1px solid #444;}
  .launcher{background:#333;color:#eee;border:none;margin-right:5px;padding:5px 10px;border-radius:3px;cursor:pointer;}
  .window{position:absolute;top:50px;left:50px;width:400px;height:300px;background:#222;border:1px solid #555;border-radius:4px;display:flex;flex-direction:column;}
  .win-header{background:#111;color:#eee;padding:5px;cursor:pointer;display:flex;justify-content:space-between;align-items:center;font-size:0.9em;}
  .win-close{background:none;border:none;color:#eee;cursor:pointer;font-weight:bold;}
  #files-window, #notepad-window{display:none;}
  /* Files app */
  #file-view{flex:1;padding:5px;overflow:auto;background:#222;}
  .fs-item{padding:2px 4px;margin:2px 0;border-radius:3px;cursor:pointer;}
  .fs-item:hover{background:#333;}
  #files-path{font-size:0.9em;color:#aaa;padding:2px 5px;}
  /* Notepad */
  #tabs{display:flex;background:#111;height:30px;}
  .tab{padding:5px 10px;border-right:1px solid #444;cursor:pointer;color:#eee;}
  .tab.active{background:#222;}
  #new-tab{border-left:none;background:#333;color:#eee;border:none;padding:5px 10px;cursor:pointer;}
  #editor{flex:1;background:#111;color:#eee;border:none;font-family:monospace;font-size:0.9em;padding:5px;}
</style>
</head>
<body>
<div id="desktop">
  <div id="taskbar">
    <button id="open-files" class="launcher">Files</button>
    <button id="open-notepad" class="launcher">Notepad</button>
  </div>

  <!-- Files Window -->
  <div id="files-window" class="window">
    <div class="win-header">
      <span>Files</span>
      <button class="win-close">&times;</button>
    </div>
    <div id="file-view">
      <div id="files-path">/</div>
      <div id="fs-list"></div>
    </div>
  </div>

  <!-- Notepad Window -->
  <div id="notepad-window" class="window">
    <div class="win-header">
      <span>Notepad</span>
      <button class="win-close">&times;</button>
    </div>
    <div id="tabs"></div>
    <textarea id="editor"></textarea>
  </div>
</div>

<script>
/* ---------- Utility ----------
*/
function $(id){return document.getElementById(id);}
function createEl(tag,cls,text){
  const el=document.createElement(tag);
  if(cls)el.className=cls;
  if(text!==undefined)el.textContent=text;
  return el;
}

/* ---------- Taskbar ----------
*/
$('open-files').onclick=function(){showWindow('files-window');};
$('open-notepad').onclick=function(){showWindow('notepad-window');};

function showWindow(id){
  const w=$('#'+id);
  if(w.style.display==='none' || !w.style.display) w.style.display='flex';
}

/* ---------- Window close ----------
*/
document.querySelectorAll('.win-close').forEach(btn=>{
  btn.onclick=function(){
    this.parentElement.parentElement.style.display='none';
  };
});

/* ---------- Files App ----------
*/
const fileSystem={
  '/':{bin:{},etc:{},home:{user:{Documents:{},Downloads:{},Pictures:{}}},usr:{},var:{}}
};

let currentPath='/';

function renderFiles(){
  const list=$('#fs-list');
  list.innerHTML='';
  const parts=currentPath.split('/').filter(Boolean);
  let node=fileSystem['/'];
  for(const p of parts)node=node[p];
  Object.keys(node).forEach(name=>{
    const item=createEl('div','fs-item',name);
    if(typeof node[name]==='object'){
      item.onclick=function(e){if(e.detail===2){navigateTo(currentPath+name+'/');}};
    }else{
      // files are ignored
    }
    list.appendChild(item);
  });
}
function navigateTo(path){
  currentPath=path;
  $('#files-path').textContent=currentPath;
  renderFiles();
}
$('#files-up').onclick=function(){navigateTo('/');};
renderFiles();

/* ---------- Notepad App ----------
*/
let tabs=[];
const STORAGE_KEY='notepad-tabs';
loadTabs();

function loadTabs(){
  const data=localStorage.getItem(STORAGE_KEY);
  if(data)tabs=JSON.parse(data); else tabs=[{id:Date.now(),content:''}];
  renderTabs();
}
function saveTabs(){localStorage.setItem(STORAGE_KEY,JSON.stringify(tabs));}

function renderTabs(){
  const tabBar=$('#tabs');
  tabBar.innerHTML='';
  tabs.forEach((t,i)=>{
    const tab=createEl('div','tab',t.id);
    if(i===activeTabIndex)tab.classList.add('active');
    tab.onclick=function(){switchTab(i);};
    tabBar.appendChild(tab);
  });
  $('#new-tab').onclick=function(){addTab();};
  tabBar.appendChild($('#new-tab'));
}

let activeTabIndex=0;
function switchTab(idx){
  if(activeTabIndex===idx)return;
  tabs[activeTabIndex].content=$('#editor').value;
  activeTabIndex=idx;
  $('#editor').value=tabs[idx].content;
  renderTabs();
}
function addTab(){
  const newId=Date.now();
  tabs.push({id:newId,content:''});
  switchTab(tabs.length-1);
  saveTabs();
}

$('#editor').addEventListener('input',()=>{
  if(activeTabIndex!==null)tabs[activeTabIndex].content=$('#editor').value;
});

/* ---------- Persist Notepad ----------
*/
window.addEventListener('beforeunload',saveTabs);

/* ---------- Initialize ----------
*/
showWindow('files-window'); // start with files open
</script>
</body>
</html>
